#### 04-05-calculette

arg1=$1
arg2=$3
ex=$2
echo $(($arg1 $ex $arg2))

case $ex in
    "+")
        echo $(($arg1 + $arg2))
        ;;
    "-")
        echo $(($arg1 - $arg2))
        ;;
    # "*")
    \*)
        echo $(($arg1 * $arg2))
        ;;
    "/")
        if [ $arg2 -ne 0 ]
        then
            echo $(($arg1 / $arg2))
        else
            echo "除数不能为0"
        fi
        ;;
    *)
        echo "不支持的运算符"
        ;;
esac

#### 直接通过 awk 读取文件，然后在 NF字段数 的范围内通过 $i 下标遍历

awk '{
    for (i = 1; i <= NF; i++) {
        seen[$i]++
    }
}
END {
    for (w in seen)
        print w, seen[w]
}' "$1"

#### 2. awk

ls -l | awk '
NR > 1 { sum[$4] += $5 }
END {
    for (g in sum)
        print g, sum[g]
}'

